#include <stdio.h>
#include <math.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        double x[1000];
        double y[1000];
        for (int i = 0; i < N; ++i) {
            scanf("%lf %lf", &x[i], &y[i]);
        }
        double maxLen = 0.0;
        for (int i = 0; i < N; ++i) {
            for (int j = i + 1; j < N; ++j) {
                double dx = x[j] - x[i];
                double dy = y[j] - y[i];
                double dist = sqrt(dx * dx + dy * dy);
                if (dist > maxLen) maxLen = dist;
            }
        }
        printf("%.10f\n", maxLen);
    }
    return 0;
}

