  const N = Number(input[idx++]);
  const xs = new Array(N);
  const ys = new Array(N);
  for (let i = 0; i < N; ++i) {
    xs[i] = Number(input[idx++]);
    ys[i] = Number(input[idx++]);
  }
  let maxLen = 0;
  for (let i = 0; i < N; ++i) {
    for (let j = i + 1; j < N; ++j) {
      const dx = xs[j] - xs[i];
      const dy = ys[j] - ys[i];
      const d = Math.hypot(dx, dy);
      if (d > maxLen) maxLen = d;
    }
